import{_ as o,o as d,c as a,a2 as l}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"修仙语录","description":"","frontmatter":{},"headers":[],"relativePath":"guide/yulu.md","filePath":"guide/yulu.md","lastUpdated":null}'),e={name:"guide/yulu.md"};function r(i,t,u,h,q,s){return d(),a("div",null,[...t[0]||(t[0]=[l('<h1 id="修仙语录" tabindex="-1">修仙语录 <a class="header-anchor" href="#修仙语录" aria-label="Permalink to &quot;修仙语录&quot;">​</a></h1><p>修仙服务器为每个Boss设计了专属台词，在开场、战斗、击杀和被击杀时都会喊话，极大增强沉浸感。</p><hr><h2 id="boss语录总览" tabindex="-1">Boss语录总览 <a class="header-anchor" href="#boss语录总览" aria-label="Permalink to &quot;Boss语录总览&quot;">​</a></h2><p>服务器共配置了 <strong>20+ Boss</strong> 的专属台词，涵盖以下场景：</p><table tabindex="0"><thead><tr><th>场景</th><th>说明</th></tr></thead><tbody><tr><td>🎬 <strong>开场</strong></td><td>Boss出现时的宣言</td></tr><tr><td>⚔️ <strong>战斗中</strong></td><td>战斗过程中随机喊话</td></tr><tr><td>💀 <strong>击杀玩家</strong></td><td>击杀玩家后的嘲讽</td></tr><tr><td>🏆 <strong>被击杀</strong></td><td>Boss死亡时的遗言</td></tr></tbody></table><hr><h2 id="克苏鲁之眼-id-4" tabindex="-1">克苏鲁之眼（ID 4） <a class="header-anchor" href="#克苏鲁之眼-id-4" aria-label="Permalink to &quot;克苏鲁之眼（ID 4）&quot;">​</a></h2><blockquote><p><strong>&quot;尔等修士，胆敢与吾一战，速速化为吾的养料！&quot;</strong></p></blockquote><ul><li>🎬 开场：又来了几个不知死活的蝼蚁...</li><li>⚔️ 战斗中：区区凡人，也敢直视吾之真身？/ 你的修行，到此为止！/ 灵气虽盛，不过尘埃！</li><li>💀 击杀：哈哈哈，不知天高地厚的蝼蚁！/ 就这点修为，也敢挑战本座？</li><li>🏆 遗言：不...不可能...吾竟败于凡人之手...</li></ul><hr><h2 id="世界吞噬者-id-13" tabindex="-1">世界吞噬者（ID 13） <a class="header-anchor" href="#世界吞噬者-id-13" aria-label="Permalink to &quot;世界吞噬者（ID 13）&quot;">​</a></h2><blockquote><p><strong>&quot;嘶嘶...吾乃深渊之口，吞尽万物！&quot;</strong></p></blockquote><ul><li>🎬 开场：腐朽之地，便是尔等葬身之所！</li><li>⚔️ 战斗中：吾之身躯，无穷无尽！/ 啃噬你的血肉，吞噬你的灵气！</li><li>💀 击杀：又一道美味入腹... / 嘶嘶...不堪一击...</li><li>🏆 遗言：吾...竟被肢解...这不可能...</li></ul><hr><h2 id="骷髅王-id-35" tabindex="-1">骷髅王（ID 35） <a class="header-anchor" href="#骷髅王-id-35" aria-label="Permalink to &quot;骷髅王（ID 35）&quot;">​</a></h2><blockquote><p><strong>&quot;擅闯地牢者，灵魂永囚于此！&quot;</strong></p></blockquote><ul><li>🎬 开场：吾乃地牢之主，尔等休想活着离开！</li><li>⚔️ 战斗中：你的骨头，将成为吾之收藏！/ 暗影之力，吞噬光明！</li><li>💀 击杀：又一个亡魂加入吾之队列...</li><li>🏆 遗言：诅咒...终于...解除了吗...</li></ul><hr><h2 id="血肉墙-id-113" tabindex="-1">血肉墙（ID 113） <a class="header-anchor" href="#血肉墙-id-113" aria-label="Permalink to &quot;血肉墙（ID 113）&quot;">​</a></h2><blockquote><p><strong>&quot;吾乃世界之壁，尔等休想越界！&quot;</strong></p></blockquote><ul><li>🎬 开场：血肉与灵魂，皆为吾之砖石！</li><li>⚔️ 战斗中：你的攻击，不过是在给吾挠痒！/ 地狱的烈焰，将焚尽你的道基！</li><li>💀 击杀：又一道灵魂砌入墙中...</li><li>🏆 遗言：世界之壁...崩塌了...新的纪元...降临...</li></ul><hr><h2 id="双子魔眼-id-125" tabindex="-1">双子魔眼（ID 125） <a class="header-anchor" href="#双子魔眼-id-125" aria-label="Permalink to &quot;双子魔眼（ID 125）&quot;">​</a></h2><blockquote><p><strong>&quot;双瞳视汝，无处遁形！&quot;</strong></p></blockquote><ul><li>🎬 开场：机械与血肉的完美融合...</li><li>⚔️ 战斗中：左眼看到了你的恐惧！/ 右眼锁定了你的灵魂！/ 你逃不掉的，修士！</li><li>💀 击杀：双瞳之下，无人生还。</li><li>🏆 遗言：机械之眼...闭上了...</li></ul><hr><h2 id="世纪之花-id-262" tabindex="-1">世纪之花（ID 262） <a class="header-anchor" href="#世纪之花-id-262" aria-label="Permalink to &quot;世纪之花（ID 262）&quot;">​</a></h2><blockquote><p><strong>&quot;丛林深处，吾已等候千年...&quot;</strong></p></blockquote><ul><li>🎬 开场：又一位修士前来献祭么？</li><li>⚔️ 战斗中：万藤缠绕，化为吾之领域！/ 自然之力，岂是人力可敌？/ 你的灵气，将成为吾之养分。</li><li>💀 击杀：回归自然吧，修士... / 丛林又多了一具肥料。</li><li>🏆 遗言：千年修行...毁于一旦...</li></ul><hr><h2 id="猪鲨公爵-id-370" tabindex="-1">猪鲨公爵（ID 370） <a class="header-anchor" href="#猪鲨公爵-id-370" aria-label="Permalink to &quot;猪鲨公爵（ID 370）&quot;">​</a></h2><blockquote><p><strong>&quot;吼——何方狂徒，胆敢惊扰本公爵？！&quot;</strong></p></blockquote><ul><li>🎬 开场：龙卷与鲨鱼，便是你的葬礼！</li><li>⚔️ 战斗中：龙卷风阵，无处可逃！/ 鲨鱼弹幕，密不透风！/ 本公爵认真起来，连自己都怕！</li><li>💀 击杀：又一头猎物葬身海底...</li><li>🏆 遗言：不...本公爵...竟然输了...东海...再见了...</li></ul><hr><h2 id="光之女皇-id-636" tabindex="-1">光之女皇（ID 636） <a class="header-anchor" href="#光之女皇-id-636" aria-label="Permalink to &quot;光之女皇（ID 636）&quot;">​</a></h2><blockquote><p><strong>&quot;光明之下，一切暗影消散！&quot;</strong></p></blockquote><ul><li>🎬 开场：尔等修士，竟敢挑战烈日之威？</li><li>⚔️ 战斗中：万剑齐发，光耀苍穹！/ 日光之舞，美到让你忘记死亡！</li><li>💀 击杀：光芒净化了一切不洁...</li><li>🏆 遗言：光...灭...了...黑暗...降临...</li></ul><hr><h2 id="月亮领主-id-398" tabindex="-1">月亮领主（ID 398） <a class="header-anchor" href="#月亮领主-id-398" aria-label="Permalink to &quot;月亮领主（ID 398）&quot;">​</a></h2><blockquote><p><strong>&quot;区区修士，也敢挑战月之主宰？！&quot;</strong></p></blockquote><ul><li>🎬 开场：吾乃星辰之主，尔等不过是尘埃中的尘埃！</li><li>⚔️ 战斗中：月之暗面，吞噬一切光明！/ 你的道，不过弹指可灭！/ 即便是大乘修士，在吾面前也不过蝼蚁！</li><li>💀 击杀：星辰之下，皆为蝼蚁... / 月之光华，便是你的葬歌。</li><li>🏆 遗言：不可能...星辰...陨落了...你...究竟是何方神圣...</li></ul><hr><h2 id="更多boss语录速览" tabindex="-1">更多Boss语录速览 <a class="header-anchor" href="#更多boss语录速览" aria-label="Permalink to &quot;更多Boss语录速览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Boss</th><th>ID</th><th>身份</th><th>经典台词</th></tr></thead><tbody><tr><td>史莱姆王</td><td>50</td><td>凝胶之王</td><td>&quot;咕噜咕噜——何人扰吾清梦？！&quot;</td></tr><tr><td>克苏鲁之脑</td><td>266</td><td>精神操控者</td><td>&quot;读心之术，尔等毫无秘密可言...&quot;</td></tr><tr><td>蜂后</td><td>222</td><td>蜂巢女王</td><td>&quot;嗡嗡嗡——擅闯蜂巢者，杀无赦！&quot;</td></tr><tr><td>史莱姆皇后</td><td>657</td><td>水晶史莱姆</td><td>&quot;吾乃水晶之躯，神圣不可侵犯！&quot;</td></tr><tr><td>毁灭者</td><td>134</td><td>钢铁巨虫</td><td>&quot;轰——吾乃大地之脊，万钧之力！&quot;</td></tr><tr><td>机械骷髅王</td><td>127</td><td>钢铁骨架</td><td>&quot;血肉已朽，钢铁永生！&quot;</td></tr><tr><td>石巨人</td><td>245</td><td>太阳神殿守卫</td><td>&quot;轰隆隆——何人唤醒丛林守护者？！&quot;</td></tr><tr><td>哀木</td><td>325</td><td>万圣之树</td><td>&quot;万圣之夜，万物哀嚎...&quot;</td></tr><tr><td>南瓜王</td><td>327</td><td>万圣之王</td><td>&quot;哈哈哈——万圣之王降临！&quot;</td></tr><tr><td>常绿尖叫怪</td><td>344</td><td>霜月之树</td><td>&quot;呜呜呜——圣诞的钟声，便是你的丧钟！&quot;</td></tr><tr><td>圣诞坦克</td><td>346</td><td>机械圣诞</td><td>&quot;滴滴滴——锁定目标：修士！&quot;</td></tr><tr><td>冰雪女王</td><td>345</td><td>冰霜之主</td><td>&quot;冰霜掌握一切，温暖只是幻觉！&quot;</td></tr><tr><td>火星飞碟</td><td>392</td><td>外星科技</td><td>&quot;滋滋——外星科技，岂是蛮荒修士可敌？&quot;</td></tr><tr><td>荷兰飞盗船</td><td>491</td><td>海盗之王</td><td>&quot;哟嚯嚯——在海上，没人能打败飞翔的荷兰人！&quot;</td></tr><tr><td>黑暗魔法师</td><td>564</td><td>古神军团</td><td>&quot;暗黑能量，汇聚于吾！&quot;</td></tr><tr><td>食人魔</td><td>576</td><td>古神军团</td><td>&quot;吼吼吼——终于来了一顿像样的美餐！&quot;</td></tr><tr><td>双足翼龙</td><td>551</td><td>古神战将</td><td>&quot;吼——古神麾下最强战将，参上！&quot;</td></tr><tr><td>拜月教教徒</td><td>439</td><td>月主信徒</td><td>&quot;仪式已启，月主即将降临！&quot;</td></tr></tbody></table><blockquote><p>共 <strong>27个Boss</strong> 拥有专属台词，涵盖开场、战斗中、击杀玩家、被击杀四个场景，每个场景有2-6条随机变体。 |</p></blockquote><hr><h2 id="全服广播语录" tabindex="-1">全服广播语录 <a class="header-anchor" href="#全服广播语录" aria-label="Permalink to &quot;全服广播语录&quot;">​</a></h2><p>除了Boss台词，服务器的全服广播也充满修仙气息：</p><h3 id="小阶突破" tabindex="-1">小阶突破 <a class="header-anchor" href="#小阶突破" aria-label="Permalink to &quot;小阶突破&quot;">​</a></h3><blockquote><p>【修仙】 {Player} 道心坚定，一举突破至 {NewRealm}！ 【修仙】 天地灵气涌动——{Player} 突破至 {NewRealm}！</p></blockquote><h3 id="大境界突破" tabindex="-1">大境界突破 <a class="header-anchor" href="#大境界突破" aria-label="Permalink to &quot;大境界突破&quot;">​</a></h3><blockquote><p>【修仙·大突破】 天道轰鸣——{Player} 成功晋升 {NewRealm}！ 【修仙·大突破】 {Player} 勘破道障，踏入全新境界 {NewRealm}！</p></blockquote><h3 id="渡劫开始" tabindex="-1">渡劫开始 <a class="header-anchor" href="#渡劫开始" aria-label="Permalink to &quot;渡劫开始&quot;">​</a></h3><blockquote><p>【渡劫】 天雷滚滚——{Player} 开始渡劫，冲击 {NewRealm}！ 【渡劫】 {Player} 引动九天雷劫，誓破 {NewRealm}！</p></blockquote><h3 id="渡劫成功" tabindex="-1">渡劫成功 <a class="header-anchor" href="#渡劫成功" aria-label="Permalink to &quot;渡劫成功&quot;">​</a></h3><blockquote><p>【渡劫·成功】 {Player} 渡过天劫，晋升 {NewRealm}！天道认可！ 【渡劫·成功】 {Player} 九死一生，终破天劫，成就 {NewRealm}！</p></blockquote><h3 id="渡劫失败" tabindex="-1">渡劫失败 <a class="header-anchor" href="#渡劫失败" aria-label="Permalink to &quot;渡劫失败&quot;">​</a></h3><blockquote><p>【渡劫·失败】 {Player} 未能扛过天劫，修为受损... 【渡劫·失败】 {Player} 天雷之下化为焦炭，渡劫失败。</p></blockquote><h3 id="天道境界晋升" tabindex="-1">天道境界晋升 <a class="header-anchor" href="#天道境界晋升" aria-label="Permalink to &quot;天道境界晋升&quot;">​</a></h3><blockquote><p>【天道】 {Player} 功德圆满，晋升 {TierName}！ 【天道】 天道垂青——{Player} 已达 {TierName}之境！</p></blockquote><h3 id="决斗系统" tabindex="-1">决斗系统 <a class="header-anchor" href="#决斗系统" aria-label="Permalink to &quot;决斗系统&quot;">​</a></h3><blockquote><p>⚔️ {Challenger} 向 {Target} 发起修仙决斗！ 🏆 {Winner} 在决斗中大胜 {Loser}！ 🤝 {Loser} 自知不敌，向 {Winner} 俯首称臣。</p></blockquote><hr><blockquote><p>📝 以上仅为语录精选，游戏中还有更多随机变体等待发现！</p></blockquote>',65)])])}const c=o(e,[["render",r]]);export{b as __pageData,c as default};
